#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long A, N, M;
        scanf("%lld %lld %lld", &A, &N, &M);
        long long result = 0;
        long long temp = A % M;
        long long power = N;
        while (power > 0) {
            if (power % 2 == 1) {
                result = (result * 10 + temp) % M;
            }
            temp = (temp * 10 + temp) % M;
            power /= 2;
        }
        printf("%lld\n", result);
    }
    return 0;
}

