        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            long A = scanner.nextLong();
            long N = scanner.nextLong();
            long M = scanner.nextLong();
            long result = 0;
            long temp = A % M;
            long power = N;
            while (power > 0) {
                if (power % 2 == 1) {
                    result = (result * 10 + temp) % M;
                }
                temp = (temp * 10 + temp) % M;
                power /= 2;
            }
            System.out.println(result);
        }
    }
}

