const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [A, N, M] = readline().split(' ').map(Number);
    let result = 0;
    let temp = A % M;
    let power = N;
    while (power > 0) {
        if (power % 2 == 1) {
            result = (result * 10 + temp) % M;
        }
        temp = (temp * 10 + temp) % M;
        power = Math.floor(power / 2);
    }
    console.log(result);
}
